import pytest
from typing import Any, Callable, Dict, List

# Assuming the function is in a module named `my_module`
# from my_module import group_by
# For the sake of a self‑contained example we define it here.
def group_by(items: List[Any], key_fn: Callable[[Any], Any]) -> Dict[Any, List[Any]]:
    result = {}
    for item in items:
        k = key_fn(item)
        result.setdefault(k, []).append(item)
    return result


