    class Person:
        def __init__(self, name, age):
            self.name = name
            self.age = age

        def __eq__(self, other):
            return isinstance(other, Person) and self.name == other.name and self.age == other.age

        def __repr__(self):
            return f"Person(name={self.name!r}, age={self.age!r})"

    people = [
